"use client";

import React, { useState, useEffect } from 'react';
import { PerfumeScene } from './PerfumeModel';
import { motion, AnimatePresence } from 'framer-motion';
import { ShoppingCart, Star, Heart, ArrowRight } from 'lucide-react';

export const Hero = () => {
  const [showInfo, setShowInfo] = useState(false);
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const checkMobile = () => {
      setIsMobile(window.innerWidth < 768);
    };
    checkMobile();
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  const infoVariants = {
    initial: { 
      opacity: 0, 
      y: isMobile ? "100%" : "-50%",
      x: isMobile ? 0 : "100%"
    },
    animate: { 
      opacity: 1, 
      y: isMobile ? 0 : "-50%",
      x: 0
    },
    exit: { 
      opacity: 0, 
      y: isMobile ? "100%" : "-50%",
      x: isMobile ? 0 : "100%"
    }
  };

  return (
    <section className="relative w-full h-screen bg-[#fafafa] overflow-hidden flex items-center justify-center pt-24">

      {/* Luxurious Background Gradient */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(255,255,255,0.8)_0%,rgba(240,240,240,1)_100%)] pointer-events-none" />

      {/* 3D Model Canvas - Fixed Full Screen, object inside moves based on state */}
      <div className="absolute inset-0 z-10">
        <PerfumeScene onSpray={() => setShowInfo(true)} interactionState={showInfo} />
      </div>

      {/* Hint Text (Fades out when interacted) */}
      <AnimatePresence>
        {!showInfo && (
            <motion.div 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 20 }}
                className="absolute bottom-16 md:bottom-12 left-1/2 -translate-x-1/2 z-20 flex flex-col items-center gap-2 pointer-events-none"
            >
                <div className="w-6 h-10 border-2 border-black/20 rounded-full flex justify-center p-1">
                    <motion.div 
                        animate={{ y: [0, 12, 0] }} 
                        transition={{ repeat: Infinity, duration: 1.5 }}
                        className="w-1 h-2 bg-black/40 rounded-full"
                    />
                </div>
                <span className="text-black/50 text-[10px] uppercase tracking-[0.3em] font-bold">
                    Interact to explore
                </span>
            </motion.div>
        )}
      </AnimatePresence>

      {/* Product Information Overlay */}
      <AnimatePresence>
        {showInfo && (
          <motion.div
            variants={infoVariants}
            initial="initial"
            animate="animate"
            exit="exit"
            transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }} // Smooth spring ease
            className="absolute bottom-0 w-full md:bottom-auto md:top-1/2 md:right-12 md:w-[450px] z-30 p-8 md:p-12 bg-white/80 md:bg-white/70 backdrop-blur-2xl md:rounded-[2rem] rounded-t-[2rem] shadow-[0_-10px_40px_-15px_rgba(0,0,0,0.1)] border border-white max-h-[75vh] md:max-h-none overflow-y-auto"
          >
            <div className="flex flex-col gap-3">
                <div className="flex items-center gap-2 text-[#c59734]">
                    <div className="flex">
                        {[1,2,3,4,5].map((i) => <Star key={i} className="w-3.5 h-3.5 fill-current" />)}
                    </div>
                    <span className="text-[11px] text-black/50 font-semibold tracking-wider">4.8 (1.2k REVIEWS)</span>
                </div>
                <h2 className="text-4xl md:text-5xl font-black text-black tracking-tighter uppercase leading-[0.9]">
                    CEO MAN <br />
                    <span className="text-[#8c5d22] text-xl font-medium tracking-widest font-serif">EAU DE PARFUM</span>
                </h2>
            </div>

            <p className="text-black/60 text-sm leading-relaxed mt-6 font-medium">
                Unleash the leader within. A powerful, sophisticated blend of fresh citrus, calming lavender, and a deep, woody base. Handcrafted for the modern trailblazer who commands the room.
            </p>

            <div className="flex flex-col gap-5 w-full mt-8">
                <div className="flex items-center justify-between border-b border-black/10 pb-2">
                    <span className="text-black/50 text-[10px] tracking-widest uppercase font-bold">Fragrance Family</span>
                    <span className="text-black text-xs font-bold font-serif italic">Woody & Spicy</span>
                </div>
                <div className="flex items-center justify-between border-b border-black/10 pb-2">
                    <span className="text-black/50 text-[10px] tracking-widest uppercase font-bold">Volume</span>
                    <span className="text-black text-xs font-bold">100ml / 3.4 fl.oz</span>
                </div>
            </div>

            <div className="flex items-end gap-3 mt-8">
                <span className="text-4xl font-black text-black">₹899</span>
                <span className="text-black/40 text-lg line-through font-semibold mb-1">₹1,199</span>
                <span className="px-2 py-1 bg-green-100 text-green-700 text-[10px] font-black uppercase tracking-widest rounded mb-2">Save 25%</span>
            </div>

            <div className="flex gap-4 w-full mt-8">
                <button className="flex-1 py-4 md:py-5 bg-black text-white font-bold uppercase tracking-[0.15em] text-xs hover:bg-[#222] active:scale-95 transition-all flex items-center justify-center gap-3 rounded-xl shadow-2xl shadow-black/20 group">
                    Add to Bag
                    <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                </button>
                <button className="p-4 md:py-5 bg-white border-2 border-black/10 hover:border-black transition-all rounded-xl group">
                    <Heart className="w-5 h-5 text-black group-hover:fill-black transition-colors" />
                </button>
            </div>

            <button 
                onClick={() => setShowInfo(false)}
                className="mt-8 text-black/40 hover:text-black text-[10px] uppercase tracking-[0.2em] font-bold transition-colors flex items-center gap-2 group mx-auto md:mx-0"
            >
                <span className="group-hover:-translate-x-1 transition-transform">←</span> Return to Canvas
            </button>
          </motion.div>
        )}
      </AnimatePresence>
    </section>
  );
};

