"use client";

import React, { useRef, useState, useMemo, useEffect } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { 
  PerspectiveCamera, 
  OrbitControls, 
  Environment, 
  Float, 
  MeshTransmissionMaterial,
  Text,
  ContactShadows,
  RoundedBox
} from '@react-three/drei';
import * as THREE from 'three';

// --- PREMIUM 3D BOTTLE COMPONENT ---
const PremiumBottle = ({ onSpray, interactionState }: { onSpray: () => void, interactionState: boolean }) => {
  const meshRef = useRef<THREE.Group>(null);
  const [hovered, setHovered] = useState(false);

  useFrame((state) => {
    if (meshRef.current) {
      // Gentle floating rotation when not interacting
      if (!interactionState) {
        meshRef.current.rotation.y = Math.sin(state.clock.elapsedTime * 0.5) * 0.2;
      } else {
        // Face forward when info is showing
        meshRef.current.rotation.y = THREE.MathUtils.lerp(meshRef.current.rotation.y, 0.1, 0.05);
      }
    }
  });

  return (
    <group 
      ref={meshRef}
      onClick={(e) => {
        e.stopPropagation();
        onSpray();
      }}
      onPointerOver={() => setHovered(true)}
      onPointerOut={() => setHovered(false)}
      scale={hovered && !interactionState ? 1.05 : 1}
      position={[0, -0.5, 0]}
    >
      <group position={[0, 0, 0]}>
        {/* OUTER GLASS BOTTLE */}
        <RoundedBox args={[1.6, 2.2, 0.9]} radius={0.15} smoothness={4}>
          <MeshTransmissionMaterial 
            backside
            backsideThickness={0.1}
            thickness={0.5}
            roughness={0}
            transmission={1}
            ior={1.5}
            chromaticAberration={0.04}
            anisotropy={0.1}
            distortion={0.1}
            distortionScale={0.2}
            temporalDistortion={0.0}
            clearcoat={1}
            attenuationDistance={2}
            attenuationColor="#ffffff"
            color="#ffffff"
          />
        </RoundedBox>

        {/* INNER LIQUID (GOLDEN) */}
        <RoundedBox args={[1.4, 2.0, 0.7]} radius={0.1} smoothness={4} position={[0, -0.05, 0]}>
          <meshPhysicalMaterial 
            color="#d4af37" 
            transmission={0.8}
            opacity={1}
            roughness={0.1}
            metalness={0.1}
            ior={1.33}
          />
        </RoundedBox>

        {/* INTERNAL TUBE */}
        <mesh position={[0, 0, 0]}>
          <cylinderGeometry args={[0.02, 0.02, 2.0, 16]} />
          <meshPhysicalMaterial color="#ffffff" transmission={0.9} opacity={0.5} transparent roughness={0.1} />
        </mesh>

        {/* BRANDING LABELS */}
        <group position={[0, 0, 0.46]}>
          <Text position={[0, 0.4, 0]} fontSize={0.12} color="#000000" font="/fonts/Inter-Bold.ttf" anchorX="center" anchorY="middle" letterSpacing={0.1}>
            BELLAVITA®
          </Text>
          <Text position={[0, 0.1, 0]} fontSize={0.28} color="#000000" font="/fonts/PlayfairDisplay-Bold.ttf" anchorX="center" anchorY="middle" letterSpacing={0.05}>
            CEO MAN
          </Text>
          <Text position={[0, -0.2, 0]} fontSize={0.08} color="#000000" font="/fonts/Inter-Regular.ttf" anchorX="center" anchorY="middle" letterSpacing={0.2}>
            EAU DE PARFUM
          </Text>
          <mesh position={[0, -0.6, 0]}>
             <planeGeometry args={[0.8, 0.2]} />
             <meshBasicMaterial color="#000" transparent opacity={0.8} />
             <Text position={[0, 0, 0.01]} fontSize={0.05} color="#D4AF37" anchorX="center" anchorY="middle" letterSpacing={0.1}>
                100 ML | 3.4 FL.OZ
            </Text>
          </mesh>
        </group>

        {/* NECK SPRAYER MECHANISM */}
        <mesh position={[0, 1.15, 0]}>
          <cylinderGeometry args={[0.25, 0.3, 0.2, 32]} />
          <meshStandardMaterial color="#D4AF37" metalness={1} roughness={0.2} />
        </mesh>
        <mesh position={[0, 1.3, 0]}>
          <cylinderGeometry args={[0.15, 0.15, 0.2, 32]} />
          <meshStandardMaterial color="#eeeeee" metalness={0.8} roughness={0.3} />
        </mesh>
        <mesh position={[0, 1.45, 0]}>
          <cylinderGeometry args={[0.2, 0.2, 0.15, 32]} />
          <meshStandardMaterial color="#D4AF37" metalness={1} roughness={0.1} />
        </mesh>

        {/* ELEGANT BLACK MAGNETIC CAP */}
        <mesh position={[0, 1.8, 0]}>
          <cylinderGeometry args={[0.35, 0.35, 0.7, 32]} />
          <meshStandardMaterial color="#111111" metalness={0.8} roughness={0.1} envMapIntensity={2} />
        </mesh>
        {/* Cap Gold Ring */}
        <mesh position={[0, 1.5, 0]}>
          <cylinderGeometry args={[0.36, 0.36, 0.05, 32]} />
          <meshStandardMaterial color="#D4AF37" metalness={1} roughness={0.1} />
        </mesh>
      </group>
    </group>
  );
};

// --- REALISTIC SPRAY PARTICLES ---
const SprayMist = ({ active }: { active: boolean }) => {
  const particles = useRef<THREE.Points>(null!);
  const particleCount = 600;

  const [positions, velocities] = useMemo(() => {
    const pos = new Float32Array(particleCount * 3);
    const vel = new Float32Array(particleCount * 3);
    for (let i = 0; i < particleCount; i++) {
      // Hidden initially
      pos[i * 3] = 0;
      pos[i * 3 + 1] = -100; 
      pos[i * 3 + 2] = 0;

      // Cone shape velocities
      const angle = Math.random() * Math.PI * 2;
      const spread = Math.random() * 0.2;
      vel[i * 3] = 0.15 + Math.random() * 0.1; // Forward speed (X)
      vel[i * 3 + 1] = Math.sin(angle) * spread; // Y spread
      vel[i * 3 + 2] = Math.cos(angle) * spread; // Z spread
    }
    return [pos, vel];
  }, []);

  useFrame(() => {
    if (!particles.current) return;
    const posArray = particles.current.geometry.attributes.position.array as Float32Array;

    if (active) {
      for (let i = 0; i < particleCount; i++) {
        // If particle is far, reset to nozzle
        if (posArray[i * 3] > 3 || posArray[i * 3 + 1] === -100) {
          posArray[i * 3] = 0.35; // Nozzle X
          posArray[i * 3 + 1] = 0.95; // Nozzle Y (relative to group)
          posArray[i * 3 + 2] = 0;    // Nozzle Z
        }

        // Move particle
        posArray[i * 3] += velocities[i * 3];
        posArray[i * 3 + 1] += velocities[i * 3 + 1];
        posArray[i * 3 + 2] += velocities[i * 3 + 2];

        // Apply gravity and slow down
        velocities[i * 3] *= 0.98;
        velocities[i * 3 + 1] -= 0.001; 
      }
    } else {
      // Hide particles when inactive
      for (let i = 0; i < particleCount; i++) {
         posArray[i * 3 + 1] = -100;
      }
    }
    particles.current.geometry.attributes.position.needsUpdate = true;
  });

  return (
    <points ref={particles}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" args={[positions, 3]} />
      </bufferGeometry>
      <pointsMaterial size={0.03} color="#ffffff" transparent opacity={0.3} depthWrite={false} blending={THREE.AdditiveBlending} />
    </points>
  );
};

// --- SCENE MANAGER (HANDLES RESPONSIVE CAMERA MOVEMENT) ---
const SceneContent = ({ onSpray, interactionState, isSpraying }: any) => {
  const groupRef = useRef<THREE.Group>(null);
  const { viewport } = useThree();

  useFrame((state) => {
    if (!groupRef.current) return;

    // Smoothly pan object based on device size and interaction state
    const isMobile = viewport.width < 5;

    // Target positions based on state
    let targetX = 0;
    let targetY = 0;

    if (interactionState) {
        if (isMobile) {
            targetX = 0;
            targetY = 1.5; // Move up on mobile
        } else {
            targetX = -viewport.width / 4; // Move left on desktop
            targetY = 0;
        }
    }

    // Lerp to target position for smooth transition
    groupRef.current.position.x = THREE.MathUtils.lerp(groupRef.current.position.x, targetX, 0.08);
    groupRef.current.position.y = THREE.MathUtils.lerp(groupRef.current.position.y, targetY, 0.08);
  });

  return (
    <group ref={groupRef}>
      <Float speed={2} rotationIntensity={0.1} floatIntensity={0.2}>
        <PremiumBottle onSpray={onSpray} interactionState={interactionState} />
        <SprayMist active={isSpraying} />
      </Float>

      {/* High Quality Shadow */}
      <ContactShadows position={[0, -2, 0]} opacity={0.6} scale={10} blur={2} far={3} color="#000000" />
    </group>
  );
};

// --- MAIN CANVAS COMPONENT ---
export const PerfumeScene = ({ onSpray, interactionState }: { onSpray: () => void, interactionState: boolean }) => {
  const [isSpraying, setIsSpraying] = useState(false);

  const handleSpray = () => {
    setIsSpraying(true);
    onSpray();
    setTimeout(() => setIsSpraying(false), 800);
  };

  return (
    <div className="w-full h-full cursor-grab active:cursor-grabbing">
      <Canvas shadows dpr={[1, 2]} camera={{ position: [0, 0, 6], fov: 45 }}>
        {/* Soft elegant lighting */}
        <ambientLight intensity={0.6} />
        <spotLight position={[5, 10, 5]} intensity={2.5} penumbra={1} angle={0.4} castShadow />
        <pointLight position={[-5, 5, -5]} intensity={1} color="#fbf9f1" />
        <pointLight position={[0, -5, 5]} intensity={0.5} color="#d4af37" />

        <SceneContent 
            onSpray={handleSpray} 
            interactionState={interactionState} 
            isSpraying={isSpraying} 
        />

        <OrbitControls 
          enableZoom={true} 
          enablePan={false} 
          minDistance={4} 
          maxDistance={10} 
          minPolarAngle={Math.PI / 4}
          maxPolarAngle={Math.PI / 1.5}
          makeDefault 
        />

        {/* City environment provides reflections for the glass and metal */}
        <Environment preset="city" background={false} />
      </Canvas>
    </div>
  );
};
